import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const API = 'https://pizza-story-backend-u6n0.onrender.com';
const LOYALTY_TARGET = 5;

const STATUS_LABELS = {
  pending: 'ממתין',
  preparing: 'בהכנה',
  outForDelivery: 'במשלוח',
  completed: 'הושלם',
};

export default function OrderHistory() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  useEffect(() => {
    if (!auth.phone) { navigate('/login'); return; }
    axios
      .get(`${API}/api/orders/history/${auth.phone}`)
      .then(res =>
        setOrders(res.data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)))
      )
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const handleReorder = order => {
    const cart = {
      toppings: order.toppings || [],
      total: order.total || 30,
    };
    localStorage.setItem('cart', JSON.stringify(cart));
    navigate('/cart');
  };

  const loyaltyCount = orders.length;
  const loyaltyProgress = loyaltyCount % LOYALTY_TARGET;
  const loyaltyPct = (loyaltyProgress / LOYALTY_TARGET) * 100;
  const ordersUntilNext = loyaltyProgress === 0 && loyaltyCount > 0 ? 0 : LOYALTY_TARGET - loyaltyProgress;
  const freePizzasEarned = Math.floor(loyaltyCount / LOYALTY_TARGET);
  const totalSpent = orders.reduce((sum, o) => sum + (o.total || 0), 0);

  if (loading) {
    return (
      <div className="max-w-md mx-auto mt-20 text-center text-gray-400">
        <div className="text-5xl mb-4 animate-bounce">🍕</div>
        <p>טוען הזמנות...</p>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto mt-0 pb-10">
      {/* Red Header */}
      <div className="flex items-center justify-between px-5 py-4 bg-tomato text-white">
        <h2 className="text-xl font-bold">ההזמנות שלי</h2>
        <button
          onClick={() => navigate('/')}
          className="bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg text-sm font-medium transition"
        >
          ← תפריט
        </button>
      </div>

      <div className="px-4 pt-4">
        <p className="text-sm text-gray-500 mb-4">
          {orders.length} הזמנות | סה"כ שולם:{' '}
          <span className="font-bold text-tomato">{totalSpent}₪</span>
        </p>

        {/* Loyalty Card */}
        <div className="bg-white rounded-2xl shadow-md p-4 mb-5 border border-orange-100">
          <div className="flex items-center gap-2 mb-3">
            <span className="text-2xl">🏆</span>
            <span className="font-bold text-gray-800 text-lg">כרטיס נאמנות</span>
          </div>

          {ordersUntilNext === 0 && loyaltyCount > 0 ? (
            <p className="text-green-600 font-bold text-sm mb-2">
              🎉 מגיעה לך פיצה חינם! פנה לעסק לממש
            </p>
          ) : (
            <p className="text-sm text-gray-600 mb-2">
              עוד{' '}
              <span className="font-bold text-tomato text-lg">{ordersUntilNext}</span>{' '}
              הזמנות לפיצה חינם!
            </p>
          )}

          <div className="w-full bg-gray-100 rounded-full h-4 overflow-hidden">
            <div
              className="bg-tomato h-4 rounded-full transition-all duration-700"
              style={{ width: `${ordersUntilNext === 0 && loyaltyCount > 0 ? 100 : loyaltyPct}%` }}
            />
          </div>
          <div className="flex justify-between text-xs text-gray-400 mt-1.5">
            <span>
              {loyaltyProgress}/{LOYALTY_TARGET} הזמנות
            </span>
            {freePizzasEarned > 0 && (
              <span className="text-green-600 font-semibold">
                🍕 ×{freePizzasEarned} נוצלו
              </span>
            )}
          </div>
        </div>

        {/* Orders List */}
        {orders.length === 0 ? (
          <div className="text-center py-16 text-gray-400">
            <div className="text-5xl mb-3">🍕</div>
            <p className="text-lg">אין הזמנות קודמות</p>
            <button
              onClick={() => navigate('/')}
              className="mt-5 bg-tomato text-white px-6 py-2 rounded-xl font-bold hover:bg-red-700 transition"
            >
              הזמן עכשיו
            </button>
          </div>
        ) : (
          <div className="space-y-3">
            {orders.map((order, idx) => (
              <div
                key={order.id || idx}
                className="bg-white rounded-xl shadow-sm p-4 border border-gray-100"
              >
                <div className="flex justify-between items-start mb-2">
                  <div className="flex items-center gap-2">
                    <span className="font-bold text-tomato text-xl">{order.total}₪</span>
                    {order.status && (
                      <span className="text-xs bg-orange-100 text-orange-600 px-2 py-0.5 rounded-full font-medium">
                        {STATUS_LABELS[order.status] || order.status}
                      </span>
                    )}
                  </div>
                  <span className="text-xs text-gray-400">
                    {order.createdAt
                      ? new Date(order.createdAt).toLocaleDateString('he-IL')
                      : ''}
                  </span>
                </div>

                <p className="text-sm text-gray-600 mb-1">
                  🍕{' '}
                  {order.toppings?.length > 0
                    ? order.toppings.join(', ')
                    : 'ללא תוספות'}
                </p>

                {(order.address || order.deliveryAddress) && (
                  <p className="text-xs text-gray-400 mb-1">
                    📍 {order.address || order.deliveryAddress}
                  </p>
                )}

                <div className="flex items-center justify-between mt-2">
                  <span className="text-xs text-gray-400">
                    {order.paymentMethod === 'cash' ? '💵 מזומן' : '💳 אשראי'}
                  </span>
                  <button
                    onClick={() => handleReorder(order)}
                    className="bg-orange-50 border border-crust text-orange-600 hover:bg-orange-100 px-3 py-1.5 rounded-lg text-sm font-bold transition"
                  >
                    🔄 הזמן שוב
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
